-- Ghana Tertiary UniConnect Dataset - part 12
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'cug_theology_leadership_and_humanities_theology', u.id, f.id, 'Theology' from public.universities u join public.faculties f on f.source_id = 'cug_theology_leadership_and_humanities' where u.source_id = 'cug' and not exists (select 1 from public.departments where source_id = 'cug_theology_leadership_and_humanities_theology' or (university_id = u.id and name = 'Theology'));
update public.departments set source_id = coalesce(source_id, 'cug_theology_leadership_and_humanities_theology'), faculty_id = (select id from public.faculties where source_id = 'cug_theology_leadership_and_humanities') where source_id = 'cug_theology_leadership_and_humanities_theology' or (name = 'Theology' and university_id = (select id from public.universities where source_id = 'cug'));
